head.script:
// id       : op_204_02_07b 
// 이름     : 협력업체중기투입등록
// 경로     : 물류/협력업체/작업계획/하역/
// 작 성 자 : 조성빈
// 작 업 일 : 2026-02-10
// 사용계정 : 내부
// 비고     :  ***
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.onpageload = function() {
	// String sUserClsCd=LoginUtil.getLoginDTO( "userClsCd" );
    // 현재일자
    scwin.toDay = $c.date.getServerDateTime("yyyyMMdd");

    scwin.sUserId     = $c.data.getMemInfo("userId");
    scwin.sUserClsCd  = $c.gus.cfIsNull($c.data.getMemInfo("userClsCd"))  ? "" : $c.data.getMemInfo("userClsCd");
    scwin.sClntNo     = $c.gus.cfIsNull($c.data.getMemInfo("clntNo"))     ? "" : $c.data.getMemInfo("clntNo");
    scwin.sClntNm     = $c.gus.cfIsNull($c.data.getMemInfo("clntNm"))     ? "" : $c.data.getMemInfo("clntNm");

	/*
	사용자 구분(그룹코드:ZZ010)
	01:그룹사
	02:협력업체&고객
	03:선사
	04:화주
	05:자가운송업체
	*/
	scwin.oNullChk_str        = "";   //장비존재여부.  (N:존재함,Y:존재안함.)
	scwin.eqCd_str            = "";   //장비코드
	scwin.eqSmallCd_str       = "";   //중기차량단축코드
	scwin.eqNm_str            = "";	//중기명
	scwin.eqNrmCd_str         = ""; 	//중기규격코드
	scwin.eqNrmNm_str         = ""; 	//중기규격이름	 	
	scwin.AfterProcessCurPos  = "";   //row(줄) 위치 
	scwin.eqKndCd             = "";   // 중기코드
	scwin.savePosCursor       = 0;



};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        var dateStr = scwin.toDay;
        ica_workDate.setValue(dateStr);
        if (scwin.sUserClsCd != "01") {
            ed_reqMchtCd.setValue(scwin.sClntNo);
            ed_reqMchtNm.setValue(scwin.sClntNm);  
            $c.gus.cfEnableObj(ed_reqMchtCd, false);    
            $c.gus.cfEnableObj(ed_reqMchtNm, false);	
        }
        $c.gus.cfDisableBtn([btn_save]); // btn_save

        $p.setTimeout(function() {
            // ed_reqMchtCd.setValue("900026");
            // ica_workDate.setValue("20070314");
        }, {"delay":50});

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    if (scwin.sUserClsCd != "01" && disGubun==1) {
        return;
    }
    var rtnList= new Array();  // 공통POP-UP -> 요청화면 
    switch (disGubun) {
        case 1:   
            // 중기협력업체	 팝업	
            udc_reqMcht.setSelectId('retrieveHeavyMachineryClntInfo');
            udc_reqMcht.cfCommonPopUp(scwin.udc_reqMcht_callBackFunc	// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch					// 전체검색허용여부	("F")
                                    ,null				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 
            break;
    }	
}

//-------------------------------------------------------------------------
// 중기 투입 요청 현황 , 중기 배정 결과 조회
//-------------------------------------------------------------------------
scwin.f_qeryList = async function (){
    if (!await $c.gus.cfValidate([ed_reqMchtCd, ica_workDate])) {	// 본선관리번호, 작업일자
        return;
    }
    ds_QueryCondition.set("clntNo", ed_reqMchtCd.getValue());   // 거래처번호
    ds_QueryCondition.set("wrkDt", ica_workDate.getValue());     // 작업일자
    $c.sbm.execute(sbm_RetrieveAssignHeavyEquip);

};

//-------------------------------------------------------------------------
//  팝업을 띄우는 함수,  파라미터 -- >  row,colid,data   
//-------------------------------------------------------------------------
scwin.f_popupChk = async function (row, colid, data) {
 	var rtnList = new Array();
	var cur_rowpos = ds_CooperationCompanyHeavyEquipAssign.getRowPosition();
	var pEqCd = "";

	if (await scwin.f_rowStateView(row) == "F") { 
		return;
	}

 	//중기단축번호 
 	if (colid == "vehclShortCd"){

		var arrParam = new Array();

		pCode = ds_CooperationCompanyInputHeavyEquip.getCellData(row, "vehclShortCd");
		pEqCd = ds_CooperationCompanyInputHeavyEquip.getCellData(row, "eqCd");
		pName = '';

		arrParam[0] = "";    				//assgnLobranCd점소코드
		arrParam[1] = ds_CooperationCompanyHeavyEquipAssign.getCellData(ds_CooperationCompanyHeavyEquipAssign.getRowPosition(),"eqKndCd"); //eqKndCd중기종류
		arrParam[2] = ed_reqMchtCd.getValue();	//clntCd거래처코드
		arrParam[3] = ds_CooperationCompanyHeavyEquipAssign.getCellData(ds_CooperationCompanyHeavyEquipAssign.getRowPosition(),"wrkDt");   //usblDt작업계획일지
		arrParam[4] = pCode;		  		//eqNo
		arrParam[5] = "";					//eqNm
		arrParam[6] = 'T';					//T,F구분
		arrParam[7] = 'T';					//T,F구분

		// rtnList = window.showModalDialog("/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.jsp", arrParam, "dialogHeight:430px; dialogWidth:600px; resizable=no; help:no; status:no; center=true; "); 

        let win_url = "/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml";
        let opts = {
            id : "ediCallPop"
            , popupName : ""
            , modal : true
            , type : "browserPopup"
            , width : 1200
            , height : 600
            , title : ""
        };
        var rtnList = await $c.win.openPopup(win_url, opts, arrParam);
		if (rtnList != null) {
            var nullchkstr = rtnList[0];

		    scwin.oNullChk_str       = "N";               	//장비존재여부.  (N:존재함,Y:존재안함.)
		    var v0  = rtnList[0];	// 중기차량단축코드
		    var v1  = rtnList[1];	// 중기번호
		    var v2  = rtnList[2];	// 중기명
		    var v3  = rtnList[3];	// 중기규격이름
		    var v11 = rtnList[11];	// 중기규격코드
		    var v12 = rtnList[12];	// 장비코드
		    var v15 = rtnList[15];	// 중기코드

		    if (nullchkstr != null) {
                if (pEqCd == v12 ) {
                    return;
                }
                if (v12 != null || v12 != ""){
                    scwin.eqCd_str = v12;    //장비코드
                }
                if (v0  != null || v0  != ""){
                    scwin.eqSmallCd_str = v0;	//중기차량단축코드
                }
                if (v11 != null || v11 != ""){
                    scwin.eqNrmCd_str = v11; 	//중기규격코드
                }
                if (v3  != null || v3  != ""){
                    scwin.eqNrmNm_str = v3; 	//중기규격이름	 		
                }
                if (v15 != null || v15 != ""){
                    scwin.eqKndCd = v15;	// 중기코드
                }
                scwin.AfterProcessCurPos = row;       //row(줄) 위치 

                if (v1  != null || v1  != ""){
                    scwin.eqNm_str = v1;	    //중기번호
                }else{
                    scwin.eqNm_str = v2;	    //중기명
                }

                // -------------------------------------
                // 중복되어 있는지 확인하는 루틴.	 	
                ds_HeavyEquipInputPossibleCheckCondition.set("wrkIndictNo", ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkIndictNo")); //하역지시번호
                ds_HeavyEquipInputPossibleCheckCondition.set("eqCd", v12);  //장비코드
                ds_HeavyEquipInputPossibleCheckCondition.set("wrkStDtm", ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkStDtm")); //작업시작시간
                ds_HeavyEquipInputPossibleCheckCondition.set("wrkEndDtm", ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkEndDtm")); //작업종료시간
                $c.sbm.execute(sbm_HeavyEquipInputPossibleCheck);
                // ---------------------------------------	
         	}
	 	} else {	 	
		    scwin.oNullChk_str          = "Y";      // 장비존재여부.  (N:존재함,Y:존재안함.)
		    scwin.eqCd_str              = "";       // 장비코드
		    scwin.eqSmallCd_str         = "";       // 중기차량단축코드
		    scwin.eqNm_str              = "";	    // 중기명
		    scwin.eqNrmCd_str           = ""; 	    // 중기규격코드
		    scwin.eqNrmNm_str           = ""; 	    // 중기규격이름	 		
		    scwin.AfterProcessCurPos    = row;      // row(줄) 위치 
		    return;
	 	}
 	}
};

//-------------------------------------------------------------------------
// 팝업 중복여부 이후 진행 함수
//-------------------------------------------------------------------------
scwin.f_AfterProcess = async function () {
   var cur_rowpos = ds_CooperationCompanyHeavyEquipAssign.getRowPosition();
   var row = scwin.AfterProcessCurPos;
   if (scwin.oNullChk_str == "N") {
        if (ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "eqKndCd") != scwin.eqKndCd) {
            await $c.gus.cfAlertMsg("장비코드["+scwin.eqCd_str+"]은  중기종류가 ["+scwin.eqNrmNm_str+"] 이며 요청한 중기종류가 아닙니다.  단축번호를 다시 선택해 주세요. ");
            ds_CooperationCompanyInputHeavyEquip.setCellData(row, "vehclShortCd", "");
            ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqCd", "");
            ds_CooperationCompanyInputHeavyEquip.setCellData(row, "vehclNoEqNm", "");
            ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqKndCd", "");
            ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqKndNm", "");
            ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqNrmCd", "");
            ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqNrmNm", "");
            return;
        }

        if (scwin.f_doubleChk(scwin.eqCd_str, ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkIndictNo")) == "F") {
            await $c.gus.cfAlertMsg("["+scwin.eqCd_str+"]은 중복된 장비코드입니다.  단축번호를 다시 선택해 주세요. ");
            return;
        }

        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "wrkIndictNo"         , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkIndictNo"));            // *작업지시번호
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqCd"                , scwin.eqCd_str);                                                                          // *장비코드
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "vehclShortCd"        , scwin.eqSmallCd_str);                                                                     // 중기차량단축코드
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "vehclNoEqNm"         , scwin.eqNm_str);	                                                                        // 중기명
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "clntNo"              , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "clntNo"));                 // * 거래처번호
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqKndCd"             , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "eqKndCd")); 	            // 중기종류코드
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqKndNm"             , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "eqKndNm")); 	            // 중기종류명
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqNrmCd"             , scwin.eqNrmCd_str); 	                                                                    // 중기규격코드
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "eqNrmNm"             , scwin.eqNrmNm_str);                                                                       // eqNrmNm_str
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "nesEqNrmCd"          , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "nesEqNrmCd"));             // *필요장비규격코드
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "tformWrkImpleKndCd"  , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "tformWrkImpleKndCd"));     // *변형작업도구종류코드
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "wrkStpCd"            , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkStpCd"));               // *작업단계코드
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "wrkStDt"             , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkStDt"));	            // 작업시작일자
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "wrkStHh"             , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkStHh"));	            // 작업시작 시,분
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "wrkEndDt"            , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkEndDt"));	            // 작업종료일자
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "wrkEndHh"            , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkEndHh"));	            // 작업종료 시,분
        ds_CooperationCompanyInputHeavyEquip.setCellData(row, "assgnSeq"            , ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "assgnSeq"));	            // 배정순번

	}      	 	 	
};

//-------------------------------------------------------------------------
// Row 상태에 대한 체크한 후 진행값 반환 ; 리턴값-->  F = 실행중지, T = 진행가능
//-------------------------------------------------------------------------
scwin.f_rowStateView = async function (row_value) {
    var rowState = ds_CooperationCompanyInputHeavyEquip.getRowStatus(row_value);
	var msg_str = "";
	var return_value = "T";
	var msg_str_tail = "\n 단축번호를 입력하실 수 없습니다.";

	if (rowState == "R") {
		msg_str = "일반[Normal]상태입니다. ";
		return_value = "F";
	}

	if (rowState == "D") {
		msg_str = "현재 삭제[Delete]상태입니다. ";
		return_value = "F";
	}
	if (rowState == "U") {
		msg_str = "현재 수정[Update]상태입니다. ";
		return_value = "F";
	}

	if (return_value == "F") {
		await $c.gus.cfAlertMsg((row_value + 1)+ " 번줄은 " + msg_str + msg_str_tail);
		return return_value;
	} else {
		return return_value;
	}
};

//-------------------------------------------------------------------------
// 단축코드( 장비코드, 작업지시번호)의  중복입력을 체크하는 함수 ; 리턴값-->  F = 실행중지, T = 진행가능
//-------------------------------------------------------------------------
scwin.f_doubleChk = function (eqCd, wrkIndictNo) {
    var rowState = "R";
	var total_cnt = ds_CooperationCompanyInputHeavyEquip.getRowCount();
	for(var i = 0 ; i < total_cnt ; i++) {
        rowState = ds_CooperationCompanyInputHeavyEquip.getRowStatus(i);
		if (rowState == "D") continue;    // 해당 Row 가 삭제상태일 경우 무시함.
		if (ds_CooperationCompanyInputHeavyEquip.getCellData(i, "eqCd") == eqCd 
         && ds_CooperationCompanyInputHeavyEquip.getCellData(i, "wrkIndictNo") == wrkIndictNo) {
			return "F";
		}
	}
	return "T";
};

  //-------------------------------------------------------------------------
  // 저장버튼 처리 
  //-------------------------------------------------------------------------
scwin.f_Save = async function (eqCd) {
    if (ds_CooperationCompanyInputHeavyEquip.getRowCount() == 0) {
        return;
    }
    // alert("저장 데이타셋="+ds_CooperationCompanyInputHeavyEquip.text);
    for(var i = 0 ; i < ds_CooperationCompanyInputHeavyEquip.getRowCount(); i++) {
        if (ds_CooperationCompanyInputHeavyEquip.getCellData(i, "eqCd") == "" 
         || ds_CooperationCompanyInputHeavyEquip.getCellData(i, "wrkIndictNo") == ""
         || ds_CooperationCompanyInputHeavyEquip.getCellData(i, "vehclShortCd") =="") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002,["단축번호"]);
            return;	    
        }
    }
	if (await $c.win.confirm(MSG_CM_CRM_001)){
        $c.sbm.execute(sbm_SaveInputHeavyEquip);
    }
};

//-------------------------------------------------------------------------
// 중기배정결과 행추가  처리 
//-------------------------------------------------------------------------
scwin.f_inputGridAddrow = async function () {
    var total_CooperationCompanyInputHeavyEquip = ds_CooperationCompanyInputHeavyEquip.getRowCount();
    var cur_rowpos = ds_CooperationCompanyHeavyEquipAssign.getRowPosition();
    if ($c.gus.cfIsNull(ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "wrkIndictNo"))) {
        await $c.gus.cfAlertMsg("선택된 작업지시번호 데이타가 없습니다.");
        return;
    } else {
        /* 	var rowCnt = 0; // SysStatus가 2가 아닌 row의 Count
            var i = 1;
            // row 갯수만큼  roop 를 돌면서 SysStatus가 2(Delete)가 아닌것을 Count 한다.
            for(i=1;i<=total_CooperationCompanyInputHeavyEquip;i++){		// row 갯수만큼 roop 를 돈다
                if (ds_CooperationCompanyInputHeavyEquip.SysStatus(i)!=2){	// SysStatus가 2(Delete)가 아니면 실행
                    rowCnt = rowCnt + 1;									// rowCount 에 + 1
                }
            }
            if (rowCnt == total_CooperationCompanyInputHeavyEquip)
        */
        if (ds_CooperationCompanyHeavyEquipAssign.getCellData(cur_rowpos, "assgnHveqCnt") == total_CooperationCompanyInputHeavyEquip) {
            await $c.gus.cfAlertMsg("요청대수 ["+total_CooperationCompanyInputHeavyEquip+" 대]를 초과했습니다.");
            return;	 
        } else {
            var rowIndex = ds_CooperationCompanyInputHeavyEquip.insertRow();
            ds_CooperationCompanyInputHeavyEquip.setRowPosition(rowIndex);
        }
    }
    $c.gus.cfDisableBtn([]);
}

//-------------------------------------------------------------------------
