scwin.f_inputGridDelrow = async function () {
    if (ds_CooperationCompanyInputHeavyEquip.getCellData(ds_CooperationCompanyInputHeavyEquip.getRowPosition(), "rsltsRegYn") == "N") {
        ds_CooperationCompanyInputHeavyEquip.deleteRow(ds_CooperationCompanyInputHeavyEquip.getRowPosition());
    } else if (ds_CooperationCompanyInputHeavyEquip.getCellData(ds_CooperationCompanyInputHeavyEquip.getRowPosition(), "rsltsRegYn") == "Y") {
        await $c.gus.cfAlertMsg("중기작업실적이 등록되어 있으므로 삭제할수 없습니다."); 
    } else {   
        ds_CooperationCompanyInputHeavyEquip.removeRow(ds_CooperationCompanyInputHeavyEquip.getRowPosition());
    }
};

