scwin.sbm_RetrieveAssignHeavyEquip_submitdone = async function (e) {
    // ds_CooperationCompanyHeavyEquipAssign" event="OnLoadCompleted(rowCnt)"
    var rowCnt1 = ds_CooperationCompanyHeavyEquipAssign.getRowCount();
  	if (rowCnt1 == 0 ){
		await $c.gus.cfAlertMsg("[중기 투입 요청 현황 정보] "+MSG_CM_ERR_003);
  	}
  	txt_totalRows.setValue(rowCnt1);
  	ds_CooperationCompanyHeavyEquipAssign.setRowPosition(scwin.savePosCursor);

    for (var i = 0 ; i < ds_CooperationCompanyHeavyEquipAssign.getRowCount() ; i ++){
        ds_CooperationCompanyHeavyEquipAssign.setCellData(i, "seq", (i+1));
    }

  	if (rowCnt1 > 0){
        scwin.ds_CooperationCompanyInputHeavyEquip_filter();
    }
    //	alert("ds_CooperationCompanyHeavyEquipAssign="+ds_CooperationCompanyHeavyEquipAssign.text);


    // ds_CooperationCompanyInputHeavyEquip" event="OnLoadCompleted(rowCnt)"
    // alert("ds_CooperationCompanyInputHeavyEquip="+ds_CooperationCompanyInputHeavyEquip.text);
    var rowCnt2 = ds_CooperationCompanyInputHeavyEquip.getRowCount();
	txt_totalRows2.setValue(rowCnt2);
  	if (rowCnt2 == 0 ){
	    //	await $c.gus.cfAlertMsg("[중기 배정 결과 정보] "+MSG_CM_ERR_003);
  	} else {
        $c.gus.cfDisableBtn([]);
  	}
};

scwin.ds_CooperationCompanyInputHeavyEquip_filter = function(){
    var v_val_1 = ds_CooperationCompanyHeavyEquipAssign.getCellData(ds_CooperationCompanyHeavyEquipAssign.getRowPosition(), "wrkIndictNo");
    var v_val_2 = ds_CooperationCompanyHeavyEquipAssign.getCellData(ds_CooperationCompanyHeavyEquipAssign.getRowPosition(), "assgnSeq");

    // if (ds_CooperationCompanyInputHeavyEquip.getCellData(row, "wrkIndictNo") == v_val_1 
    //  && ds_CooperationCompanyInputHeavyEquip.getCellData(row, "assgnSeq") == v_val_2){
    //     return true;
    // }else{
    //     return false;
    // }
    ds_CooperationCompanyInputHeavyEquip.clearFilter();
    ds_CooperationCompanyInputHeavyEquip.setColumnFilter(
        {type:'row', colIndex:'wrkIndictNo' , key: v_val_1, condition:'and'}
    );
    ds_CooperationCompanyInputHeavyEquip.setColumnFilter(
        {type:'row', colIndex:'assgnSeq'    , key: v_val_2, condition:'and'}
    );

    var rowCnt2 = ds_CooperationCompanyInputHeavyEquip.getRowCount();
	txt_totalRows2.setValue(rowCnt2);
};

scwin.gr_CooperationCompanyHeavyEquipAssign_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.ds_CooperationCompanyInputHeavyEquip_filter();
};

scwin.gr_CooperationCompanyInputHeavyEquip_oncellclick = function (Row, columnIndex, Colid) {
    var return_value = ds_CooperationCompanyInputHeavyEquip.getRowStatus(Row);
	if (Colid == "vehclShortCd"){
	    if (return_value == "R" 
         || return_value == "D") {    
			gr_CooperationCompanyInputHeavyEquip.setCellReadOnly(Row, "vehclShortCd", true);
        } else {
			gr_CooperationCompanyInputHeavyEquip.setCellReadOnly(Row, "vehclShortCd", false);
			// gr_CooperationCompanyInputHeavyEquip.ColumnProp("vehclShortCd","Edit")='AlphaNum';
		    // gr_CooperationCompanyInputHeavyEquip.ColumnProp('vehclShortCd','EditStyle')='Popup';
        }
    }
};

scwin.gr_CooperationCompanyInputHeavyEquip_onafteredit = function (row, columnIndex, value) {
    var colid = gr_CooperationCompanyInputHeavyEquip.getColumnID(columnIndex);
    var data  = ds_CooperationCompanyInputHeavyEquip.getCellData(row, columnIndex);
    scwin.f_popupChk(row, colid, value);
};

scwin.gr_CooperationCompanyInputHeavyEquip_oneditend = function (row, columnIndex, value) {
    var Colid = gr_CooperationCompanyInputHeavyEquip.getColumnID(columnIndex);
    switch (Colid) {
        case "vehclShortCd":
            if(value.length > 0  
            && ds_CooperationCompanyInputHeavyEquip.getCellData(row, "vehclShortCd") != value){
                scwin.gr_CooperationCompanyInputHeavyEquip_onafteredit(row, columnIndex, value);
            }
        break;
    }
};

scwin.gr_CooperationCompanyInputHeavyEquip_ontextimageclick = function (row, columnIndex) {
    var colid = gr_CooperationCompanyInputHeavyEquip.getColumnID(columnIndex);
    var data  = ds_CooperationCompanyInputHeavyEquip.getCellData(row, columnIndex);
    scwin.f_popupChk(row, colid, data);
};

